// Parse caller details from AT or Twilio payload
const body = $input.first().json.body || $input.first().json;

// Africa's Talking fields
const callerPhone = body.callerNumber || body.From || body.caller || '';
const sessionId   = body.sessionId   || body.CallSid || '';
const isIncoming  = true;

return [{
  json: {
    caller_phone: callerPhone,
    session_id:   sessionId,
    provider:     body.callerNumber ? 'africas_talking' : 'twilio',
    received_at:  new Date().toISOString(),
  }
}];
